#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    int *queries = (int*)malloc(T * sizeof(int));
    int maxN = 0;
    for (int i = 0; i < T; ++i) {
        scanf("%d", &queries[i]);
        if (queries[i] > maxN) maxN = queries[i];
    }
    const int MOD = 15746;
    int *dp = (int*)malloc((maxN + 2) * sizeof(int)); // +2 to safely access dp[2]
    dp[0] = 0; // unused
    if (maxN >= 1) dp[1] = 1;
    if (maxN >= 2) dp[2] = 2;
    for (int i = 3; i <= maxN; ++i) {
        dp[i] = (dp[i-1] + dp[i-2]) % MOD;
    }
    for (int i = 0; i < T; ++i) {
        printf("%d\n", dp[queries[i]]);
    }
    free(queries);
    free(dp);
    return 0;
}

