import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    queries = list(map(int, data[1:1+T]))
    maxN = max(queries)
    MOD = 15746
    dp = [0] * (maxN + 2)
    if maxN >= 1:
        dp[1] = 1
    if maxN >= 2:
        dp[2] = 2
    for i in range(3, maxN + 1):
        dp[i] = (dp[i-1] + dp[i-2]) % MOD
    out = '\n'.join(str(dp[n]) for n in queries)
    sys.stdout.write(out)

if __name__ == "__main__":
    main()

